// Dynamically resolved singleton instance of Mem0 Client (MemoryClient or Memory)
let memoryInstance: any = null;

async function getMemoryInstance(apiKey?: string) {
	if (memoryInstance) {
		return memoryInstance;
	}

	try {
		const mem0ApiKey = process.env.MEM0_API_KEY || process.env.MEM0_PLATFORM_API_KEY;
		if (mem0ApiKey) {
			const { MemoryClient } = await import("mem0ai");
			memoryInstance = new MemoryClient({ apiKey: mem0ApiKey });
			return memoryInstance;
		}

		// Fallback to OSS client
		const { Memory } = await import("mem0ai/oss");
		const openaiKey = process.env.OPENAI_API_KEY || apiKey || "";

		const config: any = {
			vectorStore: {
				provider: "memory",
				config: {
					collectionName: "zenuxs_memories",
				},
			},
		};

		if (openaiKey) {
			config.embedder = {
				provider: "openai",
				config: {
					apiKey: openaiKey,
				},
			};
			config.llm = {
				provider: "openai",
				config: {
					apiKey: openaiKey,
				},
			};
		}

		memoryInstance = new Memory(config);
		return memoryInstance;
	} catch (err) {
		console.warn("Failed to initialize Mem0 client:", err);
		return null;
	}
}

