export async function searchMemory(query: string, context: MemoryContext): Promise<string[]> {
	try {
		const mem = await getMemoryInstance(context.apiKey);
		if (!mem) {
			return [];
		}

		const memoryKey = `user_${context.userId}_project_${context.projectName}`;
		let results: any = null;

		if (typeof mem.search === "function") {
			if (mem.constructor && mem.constructor.name === "MemoryClient") {
				results = await mem.search(query, {
					filters: { user_id: memoryKey },
				});
			} else {
				results = await mem.search(query, {
					filters: { userId: memoryKey },
				});
			}
		}

		if (results) {
			const items = Array.isArray(results) ? results : (results.results ?? []);
			if (items.length > 0) {
				return items.map((r: any) => r.memory || r.content || String(r));
			}
		}
	} catch (err) {
		console.warn("Failed to search memories in Mem0:", err);
	}
	return [];
}

export function getProjectName(workspaceRoot: string): string {
	try {
		const pkgPath = path.join(workspaceRoot, "package.json");
		if (fs.existsSync(pkgPath)) {
			const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));
			if (pkg.name) {
				return pkg.name.replace(/[^a-zA-Z0-9_]/g, "_");
			}
		}
	} catch (err) {
		// ignore and fallback
	}
	return path.basename(workspaceRoot).replace(/[^a-zA-Z0-9_]/g, "_") || "unknown_project";
}

