import * as fs from "node:fs";
import * as path from "node:path";
import { createHash } from "node:crypto";
import { HuggingFaceEmbedding } from "@llamaindex/huggingface";

const RAG_DIR = ".rag-index";
const HASHES_FILE = "hashes.json";
const INDEX_FILE = "index.json";

const ALLOWED_EXTENSIONS = new Set([
	".ts", ".js", ".mjs", ".cjs", ".jsx", ".tsx", ".md",
]);
const SKIP_DIRS = new Set(["node_modules", "dist", ".git", RAG_DIR, "build", ".bun", ".cache"]);

const CHUNK_LINES = 80;
const CHUNK_OVERLAP = 10;

export interface Chunk {
	id: number;
	text: string;
	filePath: string;
}

interface FileEntry {
	path: string;
	content: string;
	hash: string;
}

interface PersistedIndex {
	chunks: Chunk[];
	embeddings: number[][];
}

export interface IndexState {
	chunks: Chunk[];
	embeddings: number[][];
}

function scanFiles(rootDir: string): FileEntry[] {
	const results: FileEntry[] = [];
	function walk(dir: string) {
		let entries: fs.Dirent[];
		try {
			entries = fs.readdirSync(dir, { withFileTypes: true });
		} catch {
			return;
		}
		for (const entry of entries) {
			const fullPath = path.join(dir, entry.name);
			if (entry.isDirectory()) {
				if (!SKIP_DIRS.has(entry.name) && !entry.name.startsWith(".")) {
					walk(fullPath);
				}
			} else if (entry.isFile()) {
				const ext = path.extname(entry.name).toLowerCase();
				if (ALLOWED_EXTENSIONS.has(ext)) {
					try {
						const content = fs.readFileSync(fullPath, "utf-8");
						const hash = createHash("sha256").update(content).digest("hex");
						results.push({ path: fullPath, content, hash });
					} catch {
						// skip unreadable files
					}
				}
			}
		}
	}
	walk(rootDir);
	return results;
}

function chunkContent(content: string, filePath: string): Chunk[] {
	const lines = content.split("\n");
	const chunks: Chunk[] = [];
	let id = 0;
	for (let i = 0; i < lines.length; i += CHUNK_LINES - CHUNK_OVERLAP) {
		const text = lines.slice(i, i + CHUNK_LINES).join("\n").trim();
		if (text) {
			chunks.push({ id: id++, text, filePath });

}

function chunkContent(content: string, filePath: string): Chunk[] {
	const lines = content.split("\n");
	const chunks: Chunk[] = [];
	let id = 0;
	for (let i = 0; i < lines.length; i += CHUNK_LINES - CHUNK_OVERLAP) {
		const text = lines.slice(i, i + CHUNK_LINES).join("\n").trim();
		if (text) {
			chunks.push({ id: id++, text, filePath });
		}
	}
	return chunks;
}

function getRagDir(workspaceRoot: string): string {
	return path.join(workspaceRoot, RAG_DIR);
}

function indexFilePath(workspaceRoot: string): string {
	return path.join(getRagDir(workspaceRoot), INDEX_FILE);
}

function hashesPath(workspaceRoot: string): string {
	return path.join(getRagDir(workspaceRoot), HASHES_FILE);
}

function persistedHashes(workspaceRoot: string): Record<string, string> {
	try {
		return JSON.parse(fs.readFileSync(hashesPath(workspaceRoot), "utf-8"));
	} catch {
		return {};
	}
}

function saveHashes(workspaceRoot: string, entries: FileEntry[]): void {
	const h: Record<string, string> = {};
	for (const e of entries) {
		h[e.path] = e.hash;
	}
	fs.writeFileSync(hashesPath(workspaceRoot), JSON.stringify(h), "utf-8");
}

function loadIndex(workspaceRoot: string): PersistedIndex | null {
	try {
		return JSON.parse(fs.readFileSync(indexFilePath(workspaceRoot), "utf-8"));
	} catch {
		return null;
	}
}

function saveIndex(workspaceRoot: string, data: PersistedIndex): void {
	fs.writeFileSync(indexFilePath(workspaceRoot), JSON.stringify(data), "utf-8");
}

let _embedModel: HuggingFaceEmbedding | null = null;

function getEmbedModel(): HuggingFaceEmbedding {
	if (!_embedModel) {
		_embedModel = new HuggingFaceEmbedding({
			modelType: "Xenova/all-MiniLM-L6-v2",
		});
	}
	return _embedModel;
}

export async function ensureIndex(workspaceRoot: string): Promise<IndexState> {
	const ragDir = getRagDir(workspaceRoot);
	if (!fs.existsSync(ragDir)) {
		fs.mkdirSync(ragDir, { recursive: true });
	}

	const files = scanFiles(workspaceRoot);
	const oldHashes = persistedHashes(workspaceRoot);
	const changed = files.length === 0 || files.some((f) => oldHashes[f.path] !== f.hash);

	if (!changed) {
		const cached = loadIndex(workspaceRoot);
		if (cached && cached.chunks.length > 0) {
			return cached;

}

	const files = scanFiles(workspaceRoot);
	const oldHashes = persistedHashes(workspaceRoot);
	const changed = files.length === 0 || files.some((f) => oldHashes[f.path] !== f.hash);

	if (!changed) {
		const cached = loadIndex(workspaceRoot);
		if (cached && cached.chunks.length > 0) {
			return cached;
		}
	}

	const allChunks: Chunk[] = [];
	for (const file of files) {
		allChunks.push(...chunkContent(file.content, file.path));
	}

	if (allChunks.length === 0) {
		const empty: IndexState = { chunks: [], embeddings: [] };
		saveIndex(workspaceRoot, empty);
		saveHashes(workspaceRoot, files);
		return empty;
	}

	const embedModel = getEmbedModel();
	const texts = allChunks.map((c) => c.text);
	const embeddings = await embedModel.getTextEmbeddings(texts);

	const data: PersistedIndex = { chunks: allChunks, embeddings };
	saveIndex(workspaceRoot, data);
	saveHashes(workspaceRoot, files);

	return data;
}

import { HuggingFaceEmbedding } from "@llamaindex/huggingface";
import { ensureIndex, type Chunk, type IndexState } from "./indexer";

export interface RetrievalResult {
	text: string;
	filePath: string;
	score: number;
}

function cosineSimilarity(a: number[], b: number[]): number {
	let dot = 0, na = 0, nb = 0;
	for (let i = 0; i < a.length; i++) {
		dot += a[i] * b[i];
		na += a[i] * a[i];
		nb += b[i] * b[i];
	}
	const denom = Math.sqrt(na) * Math.sqrt(nb);
	return denom === 0 ? 0 : dot / denom;
}

let _embedModel: HuggingFaceEmbedding | null = null;

function getEmbedModel(): HuggingFaceEmbedding {
	if (!_embedModel) {
		_embedModel = new HuggingFaceEmbedding({
			modelType: "Xenova/all-MiniLM-L6-v2",
		});
	}
	return _embedModel;
}

export async function retrieveContext(
	query: string,
	workspaceRoot: string,
	topK: number = 5,
): Promise<{ chunks: string[]; results: RetrievalResult[] }> {
	try {
		const index: IndexState = await ensureIndex(workspaceRoot);
		if (index.chunks.length === 0 || index.embeddings.length === 0) {
			return { chunks: [], results: [] };
		}

		const embedModel = getEmbedModel();
		const queryEmb = await embedModel.getTextEmbedding(query);

		const scored: Array<{ chunk: Chunk; score: number }> = [];
		for (let i = 0; i < index.chunks.length; i++) {
			const score = cosineSimilarity(queryEmb, index.embeddings[i]);
			scored.push({ chunk: index.chunks[i], score });
		}

		scored.sort((a, b) => b.score - a.score);
		const top = scored.slice(0, topK);

		const results: RetrievalResult[] = top.map((r) => ({
			text: r.chunk.text,
			filePath: r.chunk.filePath,
			score: r.score,
		}));

		const chunks = results.map(
			(r) =>
				`[${r.filePath}] (relevance: ${(r.score * 100).toFixed(0)}%)\n${r.text}`,
		);

		return { chunks, results };
	} catch (err) {
		console.warn("RAG retrieval failed:", err);
		return { chunks: [], results: [] };
	}
}

